def gen(rng, size):
    n = max(2, min(size, 500))
    edges = []
    if rng.randint(0, 1) == 0:
        for i in range(1, n):
            edges.append([i - 1, i])
    else:
        for i in range(1, n):
            edges.append([0, i])
    good = [rng.randint(0, 1) for _ in range(n)]
    return [n, edges, good]

