from collections import deque
class Solution:
    def maxSubgraphScore(self, n, edges, good):
        if n == 1:
            return [1 if good[0] else -1]
        adj = [[] for _ in range(n)]
        for a, b in edges:
            adj[a].append(b)
            adj[b].append(a)
        weight = [1 if g else -1 for g in good]
        parent = [-1] * n
        order = []
        visited = [False] * n
        visited[0] = True
        dq = deque([0])
        while dq:
            u = dq.popleft()
            order.append(u)
            for v in adj[u]:
                if not visited[v]:
                    visited[v] = True
                    parent[v] = u
                    dq.append(v)
        children = [[] for _ in range(n)]
        for v in order:
            if parent[v] != -1:
                children[parent[v]].append(v)
        down = [0] * n
        child_sum = [0] * n
        for u in reversed(order):
            cs = 0
            for c in children[u]:
                cs += max(0, down[c])
            down[u] = weight[u] + cs
            child_sum[u] = cs
        up = [0] * n
        NEG = float('-inf')
        up[order[0]] = NEG
        for u in order:
            for c in children[u]:
                parent_up_contrib = max(0, up[u]) if up[u] != NEG else 0
                sibling_sum = child_sum[u] - max(0, down[c])
                up[c] = weight[u] + parent_up_contrib + sibling_sum
        answer = [0] * n
        for i in range(n):
            if parent[i] == -1:
                answer[i] = down[i]
            else:
                answer[i] = down[i] + max(0, up[i])
        return answer

