var maxSubgraphScore = function(n, edges, good) {
    if (n === 1) return [good[0] ? 1 : -1];
    const adj = Array.from({ length: n }, () => []);
    for (const [a, b] of edges) {
        adj[a].push(b);
        adj[b].push(a);
    }
    const weight = good.map(g => g ? 1 : -1);
    const parent = new Array(n).fill(-1);
    const order = [];
    const visited = new Array(n).fill(false);
    visited[0] = true;
    const queue = [0];
    let qi = 0;
    while (qi < queue.length) {
        const u = queue[qi++];
        order.push(u);
        for (const v of adj[u]) {
            if (!visited[v]) {
                visited[v] = true;
                parent[v] = u;
                queue.push(v);
            }
        }
    }
    const children = Array.from({ length: n }, () => []);
    for (const v of order) {
        if (parent[v] !== -1) children[parent[v]].push(v);
    }
    const down = new Array(n).fill(0);
    const childSum = new Array(n).fill(0);
    for (let idx = order.length - 1; idx >= 0; idx--) {
        const u = order[idx];
        let cs = 0;
        for (const c of children[u]) cs += Math.max(0, down[c]);
        down[u] = weight[u] + cs;
        childSum[u] = cs;
    }
    const NEG = Number.NEGATIVE_INFINITY;
    const up = new Array(n).fill(0);
    up[order[0]] = NEG;
    for (const u of order) {
        for (const c of children[u]) {
            const parentUpContrib = up[u] !== NEG ? Math.max(0, up[u]) : 0;
            const siblingSum = childSum[u] - Math.max(0, down[c]);
            up[c] = weight[u] + parentUpContrib + siblingSum;
        }
    }
    const answer = new Array(n).fill(0);
    for (let i = 0; i < n; i++) {
        if (parent[i] === -1) {
            answer[i] = down[i];
        } else {
            answer[i] = down[i] + Math.max(0, up[i]);
        }
    }
    return answer;
};
